"use client";

import { useState, useEffect } from "react";
import { useLedgerStore, DEFAULT_CATEGORIES } from "@/store/useLedgerStore";

export function AddEntryModal() {
  const isAddModalOpen = useLedgerStore((state) => state.isAddModalOpen);
  const setIsAddModalOpen = useLedgerStore((state) => state.setIsAddModalOpen);
  const addEntry = useLedgerStore((state) => state.addEntry);
  const customCategories = useLedgerStore((state) => state.customCategories);
  const addCustomCategory = useLedgerStore((state) => state.addCustomCategory);

  const allCategories = [...DEFAULT_CATEGORIES, ...customCategories];

  const [name, setName] = useState("");
  const [category, setCategory] = useState(allCategories[0]);
  const [isCustom, setIsCustom] = useState(false);
  const [customCategoryInput, setCustomCategoryInput] = useState("");
  const [amount, setAmount] = useState("");
  const [type, setType] = useState<"income" | "expense">("expense");
  const [date, setDate] = useState(new Date().toISOString().split("T")[0]);

  useEffect(() => {
    if (allCategories.length > 0 && !isCustom && !allCategories.includes(category)) {
      setCategory(allCategories[0]);
    }
  }, [allCategories, category, isCustom]);

  if (!isAddModalOpen) return null;

  const handleCategoryChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const val = e.target.value;
    if (val === "CUSTOM_OPTION") {
      setIsCustom(true);
      setCategory("");
    } else {
      setIsCustom(false);
      setCategory(val);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const numAmount = parseFloat(amount);
    if (!name.trim() || isNaN(numAmount) || numAmount <= 0) {
      alert("Please enter a valid name and positive amount.");
      return;
    }

    let finalCategory = category;
    if (isCustom) {
      const trimmedCustom = customCategoryInput.trim();
      if (!trimmedCustom) {
        alert("Please enter a custom category name.");
        return;
      }
      finalCategory = trimmedCustom;
      addCustomCategory(trimmedCustom);
    }

    addEntry({
      name: name.trim(),
      category: finalCategory,
      amount: numAmount,
      type,
      date,
    });

    // Reset and close
    setName("");
    setAmount("");
    setIsCustom(false);
    setCustomCategoryInput("");
    setCategory(allCategories[0]);
    setIsAddModalOpen(false);
  };

  return (
    <div className="fixed inset-0 bg-[#0E1116]/80 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className="bg-[#16191F] border-hairline rounded-[10px] w-full max-w-md p-6 relative shadow-2xl">
        <div className="flex justify-between items-center mb-6 border-b-hairline pb-3">
          <h2 className="font-sans text-[16px] font-medium text-[#F7F5F0]">
            Add new transaction
          </h2>
          <button
            onClick={() => setIsAddModalOpen(false)}
            className="text-[#8B8680] hover:text-[#F7F5F0] text-[18px] cursor-pointer"
          >
            ✕
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex flex-col gap-4">
          {/* Type Toggle */}
          <div className="grid grid-cols-2 gap-2 bg-[#0E1116] p-1 rounded-[8px] border-hairline">
            <button
              type="button"
              onClick={() => setType("expense")}
              className={`py-2 text-[12px] font-sans font-medium rounded-[6px] transition-colors cursor-pointer ${
                type === "expense"
                  ? "bg-[#16191F] text-[#D08077] border-hairline"
                  : "text-[#8B8680] hover:text-[#F7F5F0]"
              }`}
            >
              Expense
            </button>
            <button
              type="button"
              onClick={() => setType("income")}
              className={`py-2 text-[12px] font-sans font-medium rounded-[6px] transition-colors cursor-pointer ${
                type === "income"
                  ? "bg-[#16191F] text-[#6FAE98] border-hairline"
                  : "text-[#8B8680] hover:text-[#F7F5F0]"
              }`}
            >
              Income
            </button>
          </div>

          {/* Name */}
          <div>
            <label className="block font-sans text-[11px] uppercase tracking-wider text-[#8B8680] mb-1">
              Description / Name
            </label>
            <input
              type="text"
              required
              placeholder="e.g. Rent or Organic Groceries"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full bg-[#0E1116] border-hairline rounded-[8px] px-3 py-2 text-[13px] font-sans text-[#F7F5F0] placeholder:text-[#6B6E73] focus:outline-none focus:border-[#E0BD7D] transition-colors"
            />
          </div>

          {/* Category Dropdown */}
          <div>
            <label className="block font-sans text-[11px] uppercase tracking-wider text-[#8B8680] mb-1">
              Category
            </label>
            <select
              value={isCustom ? "CUSTOM_OPTION" : category}
              onChange={handleCategoryChange}
              className="w-full bg-[#0E1116] border-hairline rounded-[8px] px-3 py-2 text-[13px] font-sans text-[#F7F5F0] focus:outline-none focus:border-[#E0BD7D] transition-colors cursor-pointer"
            >
              {allCategories.map((cat) => (
                <option key={cat} value={cat}>
                  {cat}
                </option>
              ))}
              <option value="CUSTOM_OPTION" className="text-[#E0BD7D] font-bold">
                + Add Custom Category...
              </option>
            </select>
          </div>

          {/* Custom Category Input (Conditional) */}
          {isCustom && (
            <div>
              <label className="block font-sans text-[11px] uppercase tracking-wider text-[#E0BD7D] mb-1">
                Custom Category Name
              </label>
              <input
                type="text"
                required
                placeholder="e.g. Freelance, Dining, Subscriptions"
                value={customCategoryInput}
                onChange={(e) => setCustomCategoryInput(e.target.value)}
                className="w-full bg-[#0E1116] border border-[#E0BD7D] rounded-[8px] px-3 py-2 text-[13px] font-sans text-[#F7F5F0] placeholder:text-[#6B6E73] focus:outline-none transition-colors"
              />
            </div>
          )}

          {/* Amount */}
          <div>
            <label className="block font-sans text-[11px] uppercase tracking-wider text-[#8B8680] mb-1">
              Amount (₹)
            </label>
            <input
              type="number"
              required
              placeholder="e.g. 4500"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              className="w-full bg-[#0E1116] border-hairline rounded-[8px] px-3 py-2 text-[13px] font-mono text-[#F7F5F0] placeholder:text-[#6B6E73] focus:outline-none focus:border-[#E0BD7D] transition-colors"
            />
          </div>

          {/* Date */}
          <div>
            <label className="block font-sans text-[11px] uppercase tracking-wider text-[#8B8680] mb-1">
              Date
            </label>
            <input
              type="date"
              required
              value={date}
              onChange={(e) => setDate(e.target.value)}
              className="w-full bg-[#0E1116] border-hairline rounded-[8px] px-3 py-2 text-[13px] font-mono text-[#F7F5F0] focus:outline-none focus:border-[#E0BD7D] transition-colors cursor-pointer"
            />
          </div>

          {/* Actions */}
          <div className="flex justify-end gap-3 mt-4 border-t-hairline pt-4">
            <button
              type="button"
              onClick={() => setIsAddModalOpen(false)}
              className="px-4 py-2 font-sans text-[12px] text-[#8B8680] hover:text-[#F7F5F0] transition-colors cursor-pointer"
            >
              Cancel
            </button>
            <button
              type="submit"
              className="bg-[#E0BD7D] text-[#0E1116] font-mono font-bold text-[12px] px-6 py-2 rounded-[8px] hover:opacity-90 transition-opacity cursor-pointer"
            >
              Confirm Entry
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
