"use client";

import { useLedgerStore } from "@/store/useLedgerStore";

export function Header() {
  const setIsAddModalOpen = useLedgerStore((state) => state.setIsAddModalOpen);
  const isHydrated = useLedgerStore((state) => state.isHydrated);

  let greeting = "GOOD DAY";
  let dateStr = "";

  if (isHydrated) {
    const hour = new Date().getHours();
    if (hour < 12) {
      greeting = "GOOD MORNING";
    } else if (hour < 18) {
      greeting = "GOOD AFTERNOON";
    } else {
      greeting = "GOOD EVENING";
    }

    const today = new Date();
    dateStr = today.toLocaleDateString("en-IN", {
      day: "2-digit",
      month: "short",
      year: "numeric",
    });
  }

  return (
    <header className="flex justify-between items-center pb-6 mb-8 border-b-hairline">
      <div>
        <div className="font-mono text-[11px] text-[#8B8680] uppercase tracking-wider mb-1">
          {greeting}
        </div>
        <h1 className="font-sans font-medium text-[18px] text-[#F7F5F0]">
          Investor&apos;s ledger
        </h1>
      </div>
      <div className="flex items-center gap-4">
        <span className="font-mono text-[13px] text-[#8B8680] hidden sm:block">
          {dateStr}
        </span>
        <button
          onClick={() => setIsAddModalOpen(true)}
          className="bg-[#E0BD7D] text-[#0E1116] font-mono font-bold text-[12px] px-4 py-2 rounded-[8px] hover:opacity-90 transition-opacity cursor-pointer flex items-center gap-1"
        >
          + Add Entry
        </button>
      </div>
    </header>
  );
}
