interface LedgerStoreState {
  entries: Entry[];
  customCategories: string[];
  isHydrated: boolean;
  activeNav: string;
  isAddModalOpen: boolean;
  setActiveNav: (nav: string) => void;
  setIsAddModalOpen: (open: boolean) => void;
  hydrate: () => void;
  addEntry: (entry: Omit<Entry, "id">) => void;
  deleteEntry: (id: string) => void;
  addCustomCategory: (cat: string) => void;
}

export const useLedgerStore = create<LedgerStoreState>((set) => ({
  entries: [],
  customCategories: [],
  isHydrated: false,
  activeNav: "Dashboard",
  isAddModalOpen: false,

  setActiveNav: (nav) => set({ activeNav: nav }),
  setIsAddModalOpen: (open) => set({ isAddModalOpen: open }),

  hydrate: () => {
    try {
      // Hydrate custom categories
      const savedCustom = localStorage.getItem("ledger-dark-custom-categories");
      if (savedCustom) {
        set({ customCategories: JSON.parse(savedCustom) });
      }

      // Hydrate entries
      const data = localStorage.getItem("ledger-dark-entries");
      if (data) {
        const parsed = JSON.parse(data);
        if (Array.isArray(parsed) && parsed.length > 0) {
          set({ entries: parsed, isHydrated: true });
          return;
        }
      }
      // If empty or first load, populate with stunning default entries
      localStorage.setItem("ledger-dark-entries", JSON.stringify(INITIAL_DEFAULT_ENTRIES));
      set({ entries: INITIAL_DEFAULT_ENTRIES, isHydrated: true });
    } catch (e) {
      console.error("Failed to parse localStorage data", e);
      set({ entries: INITIAL_DEFAULT_ENTRIES, isHydrated: true });
    }
  },

  addCustomCategory: (cat) => {
    set((state) => {
      if (state.customCategories.includes(cat) || DEFAULT_CATEGORIES.includes(cat)) {
        return state;
      }
      const updated = [...state.customCategories, cat];
      try {
        localStorage.setItem("ledger-dark-custom-categories", JSON.stringify(updated));
      } catch (e) {
        console.error("Failed to save custom categories", e);
      }
      return { customCategories: updated };
    });
  },

  addEntry: (entryData) => {
    const newEntry: Entry = {
      id: crypto.randomUUID(),
      ...entryData,
      amount: Math.round(entryData.amount), // ensure no decimals
    };
    set((state) => {
      const updatedEntries = [newEntry, ...state.entries];
      try {
        localStorage.setItem("ledger-dark-entries", JSON.stringify(updatedEntries));
      } catch (e) {
        console.error("Failed to save to localStorage", e);
      }
      return { entries: updatedEntries };
    });
  },

  deleteEntry: (id) => {
    set((state) => {
      const updatedEntries = state.entries.filter((entry) => entry.id !== id);
      try {
        localStorage.setItem("ledger-dark-entries", JSON.stringify(updatedEntries));
      } catch (e) {
        console.error("Failed to save to localStorage", e);
      }
      return { entries: updatedEntries };
    });
  },
}));

export const formatIndianCurrency = (
  amount: number,
  includePrefixSign: boolean = false,
  forcePlus: boolean = false
): string => {
  const absAmount = Math.abs(amount);
  const formatted = absAmount.toLocaleString("en-IN", {
    maximumFractionDigits: 0,
  });
  if (includePrefixSign) {
    if (amount < 0) {
      return `-₹${formatted}`;
    }
    if (forcePlus && amount > 0) {
      return `+₹${formatted}`;
    }
  }
  return `₹${formatted}`;
};
