"use client";

import { useEffect } from "react";
import { useLedgerStore } from "@/store/useLedgerStore";
import { Sidebar } from "@/components/Sidebar";
import { Header } from "@/components/Header";
import { StatCards } from "@/components/StatCards";
import { ChartsRow } from "@/components/ChartsRow";
import { RecentExpenses } from "@/components/RecentExpenses";
import { BillsList } from "@/components/BillsList";
import { AddEntryModal } from "@/components/AddEntryModal";

export default function Home() {
  const isHydrated = useLedgerStore((state) => state.isHydrated);
  const activeNav = useLedgerStore((state) => state.activeNav);
  const hydrate = useLedgerStore((state) => state.hydrate);

  useEffect(() => {
    hydrate();
  }, [hydrate]);

  if (!isHydrated) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-[#0E1116] text-[#8B8680] font-mono text-[13px] animate-pulse">
        Initializing terminal...
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-[#0E1116] overflow-hidden">
      {/* Sidebar Navigation */}
      <Sidebar />

      {/* Main Content Area */}
      <main className="flex-1 px-4 py-8 md:px-10 md:py-10 overflow-y-auto max-w-7xl mx-auto w-full">
        <Header />

        {activeNav === "Dashboard" && (
          <>
            <StatCards />
            <ChartsRow />
            <RecentExpenses />
            <BillsList />
          </>
        )}

        {activeNav === "Expenses" && (
          <>
            <RecentExpenses />
            <BillsList />
          </>
        )}

        {activeNav === "Investments" && (
          <>
            <RecentExpenses />
          </>
        )}

        {activeNav === "Goals" && (
          <>
            <div className="mb-6 font-sans text-[14px] text-[#8B8680]">
              Tracked financial goals and savings milestones.
            </div>
            <StatCards />
          </>
        )}

        {activeNav === "Analytics" && (
          <>
            <div className="mb-6 font-sans text-[14px] text-[#8B8680]">
              In-depth monthly aggregation and category breakdown.
            </div>
            <ChartsRow />
          </>
        )}

        {activeNav === "Settings" && (
          <div className="bg-[#16191F] border-hairline rounded-[10px] p-6 max-w-2xl">
            <h2 className="font-sans text-[16px] font-medium text-[#F7F5F0] mb-4 border-b-hairline pb-3">
              Ledger Settings
            </h2>
            <div className="flex flex-col gap-6 text-[13px]">
              <div>
                <div className="text-[#F7F5F0] font-medium mb-1">Data Persistence</div>
                <div className="text-[#8B8680] mb-3">
                  All transactions are stored securely in your browser&apos;s local storage. No data leaves your device.
                </div>
                <button
                  onClick={() => {
                    if (confirm("Are you sure you want to reset all data to default entries?")) {
                      localStorage.removeItem("ledger-dark-entries");
                      window.location.reload();
                    }
                  }}
                  className="bg-[#D08077]/20 text-[#D08077] border border-[#D08077]/40 px-4 py-2 rounded-[6px] font-mono text-[12px] hover:bg-[#D08077]/30 transition-colors cursor-pointer"
                >
                  Reset Data to Defaults
                </button>
              </div>
              <div className="border-t-hairline pt-4">
                <div className="text-[#F7F5F0] font-medium mb-1">Appearance</div>
                <div className="text-[#8B8680]">
                  Trading terminal dark canvas active. Handcrafted matte color palette with JetBrains Mono tabular numbers.
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Modals */}
      <AddEntryModal />
    </div>
  );
}
